INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (6, "えへへっ、ありがとうございます！\nえっと…", "", 1, 11, 1060018, 1, "", "", 112411, 10);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (6, "", "", "", 91, 1060019, "", "", "", 0, "");
