INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (6, "vo_omp_7006_004", "", 0, 21, 1060025, "", "", "", "vo_omp_7006", 0);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (6, "あの人にとっては何気ない\n一言だったのかも知れないですけど\n私にはそれがとてもうれしくて", "", 1, 11, 1060026, 1, "", "", 112411, 10);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (6, "", "", "", 91, 1060027, "", "", "", 0, "");
