INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "今思うと…最初のゲリラLIVEは\nほんとうにいっぱいいっぱいでしたね", "", 1, 11, 1070016, 1, "", "", 112411, 10);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "", "", "", 91, 1070017, "", "", "", 0, "");
