INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "vo_omp_7007_002", "", 0, 21, 1070025, "", "", "", "vo_omp_7007", 0);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "ペコリーヌさまの場合は、\n空腹で締め付けられていた\n可能性もありますが…", "", 1, 11, 1070026, 1, "", "", 105931, 10);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "", "", "", 91, 1070027, "", "", "", 0, "");
