INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "omp_talk_normal", "", "", 3, 1070029, "", "", 0, 106031, 1);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "vo_omp_7007_003", "", 0, 21, 1070030, "", "", "", "vo_omp_7007", 0);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "まーたしかに、あのときの\nウヅキたちのゲリラLIVEは\nほんとにボロボロだったわね！", "", 1, 11, 1070031, 1, "", "", 106031, 10);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "", "", "", 91, 1070032, "", "", "", 0, "");
