INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "omp_talk_worry", "", "", 3, 1070034, "", "", 0, 112611, 1);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "vo_omp_7007_004", "", 0, 21, 1070035, "", "", "", "vo_omp_7007", 0);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "もうっ、キャルキャル～\nあんま言わないでよ～！\n私たちだってわかってるんだからさ～", "", 1, 11, 1070036, 1, "", "", 112611, 10);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "", "", "", 91, 1070037, "", "", "", 0, "");
