INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "omp_talk_normal2", "", "", 3, 1070039, "", "", 0, 105931, 1);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "vo_omp_7007_005", "", 0, 21, 1070040, "", "", "", "vo_omp_7007", 0);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "でも、自分たちで立ち上がって\n再び舞台に立つ姿…\nわたくし、感動いたしました", "", 1, 11, 1070041, 1, "", "", 105931, 10);
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (7, "", "", "", 91, 1070042, "", "", "", 0, "");
